import * as React from 'react';
import { Handle } from 'react-flow-renderer';
import CardContent from '@mui/material/CardContent';
import Typography from '@mui/material/Typography';
import Divider from '@mui/material/Divider';
import Box from '@mui/material/Box';
import Grid from '../vertical-divider';

const RightContent = () => {
  return (
    <div>
      <br />
      <Box
        sx={{
          position: "relative",
          left: "32px",
          width: "90%",
          height: "flex",
          backgroundColor: "#eceff1",
          borderBottomLeftRadius: "3px",
          borderTopLeftRadius: "3px"
        }}>
        <Typography
          align="right"
          variant="body1"
          style={{
            position: "relative",
            left: "-16px",
          }}>
          Data Out (Looped)
        </Typography>
      </Box>
      <br />
      <Box
        sx={{
          position: "relative",
          left: "32px",
          width: "90%",
          height: "flex",
          backgroundColor: "#eceff1",
          borderBottomLeftRadius: "3px",
          borderTopLeftRadius: "3px"
        }}>
        <Typography
          align="right"
          variant="body1"
          style={{
            position: "relative",
            left: "-16px",
          }}>
          Data Out (Joint)
        </Typography>
      </Box>
    </div>
  )
}

export default function OrdinaryLinearRegression(data) {
  return (
    <>
      <CardContent>
        <Typography variant="h5" component="div">
          Data
        </Typography>
        <Typography sx={{ mb: 1.5 }} color="text.secondary">
          Data for analysis
        </Typography>
        <Divider />

        <div style={{
          width: "300px",
          position: 'relative',
          left: "-16px",
          paddingTop: "10px"
        }}>
        <RightContent/>
        </div>
      </CardContent>

      <Handle
        type="source"
        position="right"
        id="a"
        style={{ top: 173, background: '#555' }}
        isConnectable={data.data.isConnectable}
      />
      <Handle
        type="source"
        position="right"
        id="b"
        style={{ top: 221, background: '#555' }}
        isConnectable={data.data.isConnectable}
      />
    </>
  )
}